import React, { useEffect } from "react"
import { PageTitle } from '@/components/ui/Typography';
import { PageCard } from "@/components/PageCard"
import { TextField, Grid, IconButton, Box, Typography } from "@mui/material"
import QRCode from "react-qr-code";
const QrSvg = (QRCode as any).default ?? QRCode;
import { CallStatus } from "@/types/api.types";
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import { GetUserEmail } from "@/utils/token";
import { useAuthStore } from "@/store"
import { AuthServices } from "@/api";
import { ApiGlobalStateManager } from "@/lib/api-state";
import { StatusMessage } from "@/components/StatusMessage";
import { AuthServicesError } from "@/api";

const TextFieldStyle: React.CSSProperties = {
    width: "100%"
}

export const OfflineOtp: React.FC = () => {
    const { otpSecretState, setOtpSecretState } = useAuthStore();
    const userEmail = GetUserEmail();
    const hasFetchedRef = React.useRef<boolean>(false);

    const handleCopy = () => {
        navigator.clipboard.writeText(otpSecretState.data);
    }

    useEffect(() => {
        if (!hasFetchedRef.current) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(AuthServices.GetOtpSecret(), setOtpSecretState);
        }
    }, []);

    return (
        <>
            <PageCard>
                <PageTitle>Setup offline OTP</PageTitle>
                <Box>
                    <Typography variant="body1">Follow below steps to setup offline OTP:</Typography>
                    <Box component="ol" sx={{ padding: '20px' }}>
                        <li>Install Google Authenticator: If you have not already, download and install the Google Authenticator app on your smartphone or tablet. It is available for both iOS and Android.</li>
                        <li>Click on the button below to setup offline OTP.</li>
                        <li>Scan the QR code using the Authenticator app.</li>
                        <li>Alternatively you can also add manually if scan does not work. Copy below secret key and create a new entry manually.</li>
                    </Box>
                    {
                        otpSecretState.status === CallStatus.Success &&
                        (
                            <Grid container spacing={1}>
                                <Grid size={10}>
                                    <TextField
                                            disabled
                                            id="outlined-disabled"
                                            label="Secret"
                                            defaultValue={otpSecretState.data}
                                            style={TextFieldStyle}
                                        />
                                </Grid>
                                <Grid size={1}>
                                    <IconButton aria-label="copy" size="medium" onClick={handleCopy}>
                                        <ContentCopyIcon fontSize="inherit" />
                                    </IconButton>
                                </Grid>

                            </Grid>
                        )
                    }

                </Box>
                <Box sx={{ mt: 2 }}>
                    {
                        otpSecretState.status === CallStatus.Success &&
                        (
                            <Box sx={{ height: 'auto', maxWidth: 64, width: '100%' }}>
                                <QrSvg
                                    size={200}
                                    style={{ height: "auto", maxWidth: "400" }}
                                    value={`otpauth://totp/${userEmail}?secret=${otpSecretState.data}&issuer=JNVSAlumni`}
                                    viewBox={`0 0 200 200`}
                                />
                            </Box>
                        )
                    }
                </Box>
                <StatusMessage
                    currentStatus={otpSecretState.status}
                    notStartedMessage=""
                    failureMessage={AuthServicesError.GetOtpSecretError(otpSecretState.httpStatus)}
                    correlationId={otpSecretState.correlationId}
                />
            </PageCard>
        </>
    )
}
